mapper.select:
	SELECT *
	FROM(	
		SELECT
			 INTRFC_ID AS intrfcId
			,TRX_CD AS trxCd
			,BIZ_CD AS bizCd
			,INST_CD AS instCd
			,TRX_TYPE_CD AS trxTypeCd
			,RAW_DATA AS rawData
			,ROW_NUMBER() over (order by INTRFC_ID, TRX_CD, BIZ_CD, INST_CD, TRX_TYPE_CD) as rn
		FROM TBINTRFCCOMDT
		WHERE 1=1
	
		AND INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
 	
	
		AND TRX_CD = #{trxCd, jdbcType = VARCHAR}
 	
	
		AND BIZ_CD = #{bizCd, jdbcType = VARCHAR}
 	
	
		AND INST_CD = #{instCd, jdbcType = VARCHAR}
 	
	
		AND TRX_TYPE_CD = #{trxTypeCd, jdbcType = VARCHAR}
 	
	) p
		WHERE p.rn > ((#{pageNumber , jdbcType=NUMERIC}-1) * #{pageSize , jdbcType=NUMERIC}) 
	    AND p.rn <= ((#{pageNumber , jdbcType=NUMERIC} * #{pageSize, jdbcType=NUMERIC}))

		SELECT
			count(*) cnt
		FROM 
			TBINTRFCCOMDT
		WHERE 1=1
	
		AND INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
 	
	
		AND TRX_CD = #{trxCd, jdbcType = VARCHAR}
 	
	
		AND BIZ_CD = #{bizCd, jdbcType = VARCHAR}
 	
	
		AND INST_CD = #{instCd, jdbcType = VARCHAR}
 	
	
		AND TRX_TYPE_CD = #{trxTypeCd, jdbcType = VARCHAR}

	
	SELECT
		 INTRFC_ID AS intrfcId
		,TRX_CD AS trxCd
		,BIZ_CD AS bizCd
		,INST_CD AS instCd
		,TRX_TYPE_CD AS trxTypeCd
		,RAW_DATA AS rawData
	FROM TBINTRFCCOMDT
	WHERE INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
 	AND TRX_CD = #{trxCd, jdbcType = VARCHAR}
 	AND BIZ_CD = #{bizCd, jdbcType = VARCHAR}
 	AND INST_CD = #{instCd, jdbcType = VARCHAR}
 	AND TRX_TYPE_CD = #{trxTypeCd, jdbcType = VARCHAR}

