 		,#{bizCd, jdbcType = VARCHAR}
 		,#{instCd, jdbcType = VARCHAR}
 		,#{trxTypeCd, jdbcType = VARCHAR}
 		,#{rawData}
  	)

mapper.update:
	UPDATE TBINTRFCCOMDT 
	SET
     		RAW_DATA = #{rawData}		
   	WHERE INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
	AND TRX_CD = #{trxCd, jdbcType = VARCHAR}
	AND BIZ_CD = #{bizCd, jdbcType = VARCHAR}
	AND INST_CD = #{instCd, jdbcType = VARCHAR}
	AND TRX_TYPE_CD = #{trxTypeCd, jdbcType = VARCHAR}

	DELETE FROM TBINTRFCCOMDT
	WHERE INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
 	AND TRX_CD = #{trxCd, jdbcType = VARCHAR}
 	AND BIZ_CD = #{bizCd, jdbcType = VARCHAR}
